class Solution:
    def countNumbers(self, l: str, r: str, b: int) -> int:
        def convert_to_base10(num: str, base: int) -> int:
            result = 0
            for i, digit in enumerate(reversed(num)):
                result += int(digit) * (base ** i)
            return result

        def convert_to_base_b(num: int, base: int) -> str:
            if num == 0:
                return '0'
            result = []
            while num > 0:
                result.append(str(num % base))
                num //= base
            return ''.join(reversed(result))

        def has_non_decreasing_digits(num: str) -> bool:
            for i in range(1, len(num)):
                if num[i] < num[i - 1]:
                    return False
            return True

        def count_non_decreasing_numbers_in_range(left: str, right: str, base: int) -> int:
            left_base10 = convert_to_base10(left, base)
            right_base10 = convert_to_base10(right, base)
            count = 0
            for num in range(left_base10, right_base10 + 1):
                num_base_b = convert_to_base_b(num, base)
                if has_non_decreasing_digits(num_base_b):
                    count += 1
            return count % (10 ** 9 + 7)

        return count_non_decreasing_numbers_in_range(l, r, b)
